        var token = _cts.Token;
        while (!token.IsCancellationRequested)
        {
            try
            {
                // Replaces ManualResetEvent.WaitOne().
                // WaitHandle.WaitAny wakes on EITHER a new event OR cancellation.
                WaitHandle.WaitAny(new[] { _newEvent.WaitHandle, token.WaitHandle });

